import{_ as t,o,c as r,ag as d}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"zkqes structural rename — design spec","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-05-03-zkqes-rename-design.md","filePath":"superpowers/specs/2026-05-03-zkqes-rename-design.md","lastUpdated":1777921494000}'),s={name:"superpowers/specs/2026-05-03-zkqes-rename-design.md"};function c(n,e,a,i,l,g){return o(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="zkqes-structural-rename-—-design-spec" tabindex="-1">zkqes structural rename — design spec <a class="header-anchor" href="#zkqes-structural-rename-—-design-spec" aria-label="Permalink to &quot;zkqes structural rename — design spec&quot;">​</a></h1><p><strong>Date:</strong> 2026-05-03 <strong>Status:</strong> locked, dispatch-ready <strong>Surface map:</strong> <a href="./../research/2026-05-03-zkqes-rename-analysis"><code>docs/superpowers/research/2026-05-03-zkqes-rename-analysis.md</code></a> (committed at <code>717abb0</code>) <strong>Orchestration:</strong> <a href="./../plans/2026-05-03-zkqes-rename-orchestration"><code>docs/superpowers/plans/2026-05-03-zkqes-rename-orchestration.md</code></a></p><h2 id="_0-goal-one-sentence" tabindex="-1">0. Goal (one sentence) <a class="header-anchor" href="#_0-goal-one-sentence" aria-label="Permalink to &quot;0. Goal (one sentence)&quot;">​</a></h2><p>Collapse the QKB / QIE / Identity Escrow three-tier brand hierarchy locked in <code>BRAND.md</code> (2026-05-03) into a single noun, <strong><code>zkqes</code></strong>, matching <code>zkqes.org</code> and <code>zk-QES</code> descriptor — with zero shipped-artifact migration cost (nothing on npm, nothing on Sepolia, no ceremony rounds run, all 5 V5.x tags preserved as immutable historical record).</p><h2 id="_1-locked-decisions-founder-confirmed-2026-05-03" tabindex="-1">1. Locked decisions (founder confirmed 2026-05-03) <a class="header-anchor" href="#_1-locked-decisions-founder-confirmed-2026-05-03" aria-label="Permalink to &quot;1. Locked decisions (founder confirmed 2026-05-03)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Q</th><th>Decision</th><th>Implication</th></tr></thead><tbody><tr><td><strong>Q1</strong></td><td><code>IdentityEscrowNFT.sol</code> → <strong><code>ZkqesCertificate.sol</code></strong></td><td>Names what it actually is — on-chain attestation of the QES binding. Resolves <code>identityEscrowNftAbi</code> SDK export, <code>scripts/sync-deployments.mjs</code> field name, test files, i18n strings.</td></tr><tr><td><strong>Q2</strong></td><td><strong>Delete entirely</strong> the QIE Phase-2 cluster</td><td><code>packages/qie-{core,agent,cli}/</code>, <code>deploy/mock-qtsps/</code>, <code>docs/qie/</code>, <code>fixtures/qie/</code>, <code>qie-eng</code> row from CLAUDE.md. Verified: zero <code>web/src</code> imports of <code>@qkb/qie-*</code>. Drop <code>@qkb/qie-{core,agent}</code> deps from <code>packages/web/package.json</code>. Restore from git history if Phase 2 ever resumes.</td></tr><tr><td><strong>Q3</strong></td><td><strong>Freeze 9 consensus-critical domain-separation tags; rename 4 cosmetic</strong></td><td>See §3 below for the freeze/rename split. Reduces dispatch from ~2 days to ~1 day; preserves circuit + ceremony validity; documented as a ProtocolBytes invariant in CLAUDE.md so future amendments don&#39;t accidentally rename them.</td></tr><tr><td><strong>Q4</strong></td><td><strong>Keep schema <code>$id</code> URLs as-is</strong>; 301-redirect at host level once <code>identityescrow.org</code> aliases to <code>zkqes.org</code></td><td>JSON-Schema validators may dereference these URLs. Rewriting is unsafe (validator caches) and unnecessary (redirect handles it).</td></tr><tr><td><strong>Q5</strong></td><td><strong>New <code>prove-zkqes-org</code> R2 bucket for V5+; freeze old <code>prove-identityescrow-org</code> as historical mirror</strong></td><td>R2 buckets aren&#39;t renameable in place. V5 ceremony hasn&#39;t started, so creating fresh is cheap. V3/V4 historical artifacts at the old bucket remain reachable forever.</td></tr><tr><td><strong>Q6</strong></td><td>Org placeholders canonicalize to <code>alik-eth/zkqes</code> family</td><td>Source repo: <code>alik-eth/zkqes</code> (already renamed today). GHCR: <code>alik-eth/zkqes-ceremony</code>. Homebrew tap: <code>alik-eth/homebrew-zkqes</code>. npm scope: <code>@zkqes/*</code> (founder claims pre-publish).</td></tr><tr><td><strong>Q7</strong></td><td>CLI binary: <strong><code>zkqes serve</code></strong></td><td>Affects Homebrew formula <code>bin.install</code>, npm <code>bin</code> entry, all i18n + docs + <code>CliBanner.tsx</code> + <code>useCliPresence.ts</code> (origin-pin probe must match new binary identity).</td></tr></tbody></table><h2 id="_2-naming-conventions" tabindex="-1">2. Naming conventions <a class="header-anchor" href="#_2-naming-conventions" aria-label="Permalink to &quot;2. Naming conventions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>Old</th><th>New</th></tr></thead><tbody><tr><td>Protocol noun in code</td><td><code>QKB</code> / <code>qkb</code></td><td><strong><code>Zkqes</code></strong> / <strong><code>zkqes</code></strong></td></tr><tr><td>Workspace package scope</td><td><code>@qkb/*</code></td><td><strong><code>@zkqes/*</code></strong></td></tr><tr><td>CLI binary</td><td><code>qkb</code></td><td><strong><code>zkqes</code></strong></td></tr><tr><td>Solidity contracts</td><td><code>QKBRegistryV5_2</code>, <code>QKBPresentationV5*</code></td><td><strong><code>ZkqesRegistryV5_2</code></strong>, <strong><code>ZkqesPresentationV5*</code></strong></td></tr><tr><td>Circom templates</td><td><code>QKBPresentationV5*</code>, <code>QKBLeaf*</code></td><td><strong><code>ZkqesPresentationV5*</code></strong>, <strong><code>ZkqesLeaf*</code></strong></td></tr><tr><td>Stub zkey filenames</td><td><code>qkb-v5_2-stub.zkey</code> family</td><td><strong><code>zkqes-v5_2-stub.zkey</code></strong> family</td></tr><tr><td>ABI mirror filenames</td><td><code>QKBRegistryV5_2.ts</code> etc.</td><td><strong><code>ZkqesRegistryV5_2.ts</code></strong> etc.</td></tr><tr><td>TS exports</td><td><code>QKB_DEPLOYMENTS</code>, <code>QkbNetwork</code>, <code>QkbDeployment</code>, <code>QkbError</code>, <code>qkbRegistryV5_2Abi</code>, <code>identityEscrowNftAbi</code>, etc.</td><td><strong><code>ZKQES_DEPLOYMENTS</code></strong>, <strong><code>ZkqesNetwork</code></strong>, <strong><code>ZkqesDeployment</code></strong>, <strong><code>ZkqesError</code></strong>, <strong><code>zkqesRegistryV5_2Abi</code></strong>, <strong><code>zkqesCertificateAbi</code></strong></td></tr><tr><td>GitHub repo</td><td><code>alik-eth/identityescroworg</code> (renamed today to <code>alik-eth/zkqes</code>)</td><td><strong><code>alik-eth/zkqes</code></strong> (in-repo references)</td></tr><tr><td>GHCR image</td><td><code>identityescroworg/qkb-ceremony</code></td><td><strong><code>alik-eth/zkqes-ceremony</code></strong></td></tr><tr><td>Homebrew tap</td><td><code>qkb-eth/homebrew-qkb</code></td><td><strong><code>alik-eth/homebrew-zkqes</code></strong></td></tr><tr><td>Browser CacheStorage namespace</td><td><code>qkb-circuit-artifacts-v1</code></td><td><strong><code>zkqes-circuit-artifacts-v1</code></strong></td></tr><tr><td>IPC schemas</td><td><code>qkb-witness/v1</code>, <code>qkb-tsl-update-witness/v1</code>, <code>qkb-helper@&lt;semver&gt;</code></td><td><strong><code>zkqes-witness/v1</code></strong>, <strong><code>zkqes-tsl-update-witness/v1</code></strong>, <strong><code>zkqes-helper@&lt;semver&gt;</code></strong></td></tr><tr><td>Public-facing copy</td><td>&quot;QKB&quot;, &quot;Qualified Key Binding&quot;, &quot;Identity Escrow&quot;, &quot;QIE&quot;, &quot;Qualified Identity Escrow&quot;</td><td><strong>&quot;zkqes&quot;</strong> (lowercase noun, no expansion). Two-second descriptor when needed: &quot;a zero-knowledge proof of a qualified electronic signature.&quot;</td></tr></tbody></table><h2 id="_3-frozen-consensus-critical-bytes-do-not-rename" tabindex="-1">3. Frozen consensus-critical bytes (DO NOT RENAME) <a class="header-anchor" href="#_3-frozen-consensus-critical-bytes-do-not-rename" aria-label="Permalink to &quot;3. Frozen consensus-critical bytes (DO NOT RENAME)&quot;">​</a></h2><p>These string literals are hashed (keccak256 / SHA-256 / Poseidon) into circuit-public, contract-stored, or off-chain deterministically-derived values. Renaming any of them invalidates the V5.2/V5.3 circuit + the in-flight Phase B ceremony + every existing fixture. They were chosen at design time, never published in a way users can see, and remain protocol-internal.</p><p><strong>Frozen tags (keep <code>qkb-</code> prefix forever as protocol bytes):</strong></p><table tabindex="0"><thead><tr><th>Tag</th><th>Used in</th></tr></thead><tbody><tr><td><code>&quot;qkb-rotate-auth-v1&quot;</code></td><td><code>keccak256(tag ‖ chainId ‖ registry ‖ fingerprint ‖ newWallet)</code> for rotation-auth signature gate</td></tr><tr><td><code>&quot;qkb-personal-secret-v1&quot;</code></td><td>EOA <code>personal_sign(tag + …)</code> IKM for <code>walletSecret</code> derivation</td></tr><tr><td><code>&quot;qkb-id-fingerprint-v1&quot;</code></td><td><code>FINGERPRINT_DOMAIN</code> field-element baked into V5 r1cs</td></tr><tr><td><code>&quot;qkb-walletsecret-v1&quot;</code> (SCW)</td><td>SHA-256 salt for SCW-path walletSecret</td></tr><tr><td><code>&quot;qkb-v5-walletsecret&quot;</code> (HKDF)</td><td>HKDF salt</td></tr><tr><td><code>&quot;qkb-binding-core/v1&quot;</code></td><td>Schema discriminator embedded in JCS-canonicalized binding</td></tr><tr><td><code>&quot;qkb-policy-leaf/v1&quot;</code></td><td>Same</td></tr><tr><td><code>&quot;QKB/2.0&quot;</code>, <code>&quot;QKB/1.0&quot;</code></td><td><code>version</code> field in binding JSON</td></tr><tr><td><code>&quot;qkb-default-ua&quot;</code></td><td>UA policyId in <code>fixtures/declarations/ua/policy-v1.json</code></td></tr></tbody></table><p><strong>Same posture for V4 schema discriminators</strong> (<code>&quot;qkb-v4-policy-root/v1&quot;</code>, <code>&quot;qkb-v4-trust-root/v1&quot;</code>, <code>&quot;qkb-v4-ua&quot;</code>, <code>&quot;qkb-v4-ceremony-urls/v1&quot;</code>) — these anchor V4 historical fixtures and frozen Merkle roots.</p><p><strong>Where this gets enforced:</strong> new CLAUDE.md invariant at the repo root (V6.1) — &quot;ProtocolBytes constants in code are protocol-internal byte strings, not branding. They predate the rename and stay frozen. Comments next to each constant note: <code>// frozen protocol byte string; see specs/2026-05-03-zkqes-rename-design.md §3</code>.&quot;</p><p><strong>What gets renamed (cosmetic, no protocol impact):</strong></p><ul><li><code>qkb-circuit-artifacts-v1</code> → <code>zkqes-circuit-artifacts-v1</code> (browser cache key)</li><li><code>qkb-witness/v1</code> → <code>zkqes-witness/v1</code> (IPC schema)</li><li><code>qkb-tsl-update-witness/v1</code> → <code>zkqes-tsl-update-witness/v1</code> (IPC schema)</li><li><code>qkb-v5*-stub.zkey</code> filename family → <code>zkqes-v5*-stub.zkey</code></li></ul><h2 id="_4-already-immutable-surfaces-do-not-rewrite" tabindex="-1">4. Already-immutable surfaces (DO NOT REWRITE) <a class="header-anchor" href="#_4-already-immutable-surfaces-do-not-rewrite" aria-label="Permalink to &quot;4. Already-immutable surfaces (DO NOT REWRITE)&quot;">​</a></h2><ul><li>5 V5.x tags (<code>v0.5.1-pre-ceremony</code> through <code>v0.5.5-pre-ceremony</code>) and <code>v0.5.4-cli</code> — annotation text references QKB extensively. Tags are immutable. New tag (<code>v0.6.0-zkqes-rename</code>) carries new noun.</li><li>Prior commit messages — git history is append-only; commit-message rewrites are force-pushes.</li><li>Schema <code>$id</code> URLs — see Q4.</li><li>V3/V4 R2 keys at <code>prove.identityescrow.org/{ecdsa-chain,age,ua-leaf-v4,ua-leaf-v4-v2}/</code> — see Q5.</li><li>The 9 frozen consensus-critical tags above — see §3.</li></ul><h2 id="_5-worker-assignment-4-parallel-2-lead-passes" tabindex="-1">5. Worker assignment (4 parallel + 2 lead passes) <a class="header-anchor" href="#_5-worker-assignment-4-parallel-2-lead-passes" aria-label="Permalink to &quot;5. Worker assignment (4 parallel + 2 lead passes)&quot;">​</a></h2><p>See orchestration plan for the dispatch sequence + branch structure. High-level scope per worker:</p><table tabindex="0"><thead><tr><th>Worker</th><th>Scope</th><th>Files (approx)</th></tr></thead><tbody><tr><td><strong>flattener-eng</strong></td><td><code>packages/lotl-flattener/</code> package.json + CLAUDE.md + README; nothing else of consequence</td><td>3 files</td></tr><tr><td><strong>circuits-eng</strong></td><td>8 Circom file/template renames + every reference + <code>stub-v5*.sh</code> filename family + <code>packages/circuits/CLAUDE.md</code> + circuit benchmarks. <strong>Q3=freeze means no protocol re-compile</strong> — only file/identifier renames.</td><td>~25 files</td></tr><tr><td><strong>contracts-eng</strong></td><td>24 Solidity file renames + every contract/library/interface/import decl + every deploy script + <code>IdentityEscrowNFT.sol</code> → <code>ZkqesCertificate.sol</code> (Q1) + <code>MIGRATION.md</code> + CLAUDE.md + gas-snapshot regenerate (cosmetic file-name only)</td><td>~40 files</td></tr><tr><td><strong>web-eng</strong></td><td>4 SDK ABI mirror renames + every <code>qkbRegistry*Abi</code> import sweep + <code>LandingHero.tsx</code> + i18n en.json + i18n uk.json + 6 routes + every <code>IdentityEscrowNFT</code> reference (Q1) + Dockerfile + fly.toml + <code>index.html</code> + <code>404.html</code> content (not the V5.22 <code>cp</code> step) + <code>PRIVACY.md</code> + CLAUDE.md</td><td>~60 files</td></tr><tr><td><strong>lead foundation pass</strong></td><td>root <code>package.json</code>, <code>pnpm-workspace.yaml</code>, root <code>CLAUDE.md</code>, <code>BRAND.md</code> (rewritten), root <code>README.md</code> (re-sweep), <code>Dockerfile.web</code>, <code>Caddyfile</code>, root <code>.env.example</code>, <code>package.json</code> <code>flatten</code> script ref.</td><td>~10 files</td></tr><tr><td><strong>lead CI + cookbook pass</strong></td><td><code>.github/workflows/{pages,pages-docs,release-cli}.yml</code>, <code>scripts/ceremony-coord/{*,cookbooks/fly/*}</code>, <code>scripts/{dev-chain.sh,sync-deployments.mjs}</code>, GHCR repo creation outside repo.</td><td>~30 files</td></tr><tr><td><strong>lead docs sweep</strong></td><td><code>docs/superpowers/specs/{2026-04-29,2026-04-30,2026-05-01,2026-05-03}-*.md</code> (current spec corpus only — older specs get a header note), <code>docs/superpowers/plans/{same}</code>, <code>docs/marketing/*</code> (delete or supersede), <code>docs/.vitepress/config.mts</code>, <code>docs/cli-release-homebrew/Formula/qkb.rb</code> (rename file), <code>docs/cli-release.md</code>, <code>docs/release-notes/*</code>, <code>docs/integrations.md</code>, <code>docs/index.md</code>. Older specs/plans get a one-line &quot;see commit X for rename baseline&quot; note.</td><td>~50 files</td></tr><tr><td><strong>lead QIE deletion</strong></td><td>drop <code>packages/qie-{core,agent,cli}/</code>, <code>deploy/mock-qtsps/</code>, <code>docs/qie/</code>, <code>fixtures/qie/</code>, <code>qie-eng</code> row from CLAUDE.md, drop <code>@qkb/qie-*</code> deps from web/package.json, drop CI build steps for qie packages</td><td>~70 files (deletes)</td></tr></tbody></table><h2 id="_6-tag-commit-conventions" tabindex="-1">6. Tag + commit conventions <a class="header-anchor" href="#_6-tag-commit-conventions" aria-label="Permalink to &quot;6. Tag + commit conventions&quot;">​</a></h2><ul><li>Final tag: <strong><code>v0.6.0-zkqes-rename</code></strong> (annotated, signed) on the merge commit that lands the rename train back to main.</li><li>Per-worker commits use the worker&#39;s package CLAUDE.md scope prefix (e.g., <code>circuits(rename): rename QKBPresentationV5.circom → ZkqesPresentationV5.circom</code>).</li><li>Final merge commit summarizes the four worker tracks, references the spec + orchestration plan + analysis report SHAs.</li><li>CHANGELOG entry on the rename train branch.</li></ul><h2 id="_7-verification-per-worker-before-lead-review" tabindex="-1">7. Verification (per worker, before lead review) <a class="header-anchor" href="#_7-verification-per-worker-before-lead-review" aria-label="Permalink to &quot;7. Verification (per worker, before lead review)&quot;">​</a></h2><ul><li><code>pnpm install --frozen-lockfile</code> — green (workspace topology resolves under new package names)</li><li><code>pnpm -F @zkqes/&lt;pkg&gt; typecheck</code> — green</li><li><code>pnpm -F @zkqes/&lt;pkg&gt; test</code> — green</li><li><code>pnpm -F @zkqes/&lt;pkg&gt; build</code> — green where applicable</li><li>For contracts-eng: <code>forge test</code> from the worker worktree (lead-side <code>forge test</code> from main is broken per task #65; that&#39;s a separate pre-existing issue and doesn&#39;t gate this rename)</li><li>For circuits-eng: confirm zkey filename rename works in <code>stub-v5_2.sh</code> end-to-end</li><li>For web-eng: <code>VITE_TARGET=landing pnpm -F @zkqes/web build</code> green + entry chunk size unchanged from V5.22 baseline</li><li>ProtocolBytes invariant scan: <code>rg -n &#39;^\\s*const.*=\\s*&quot;qkb-&#39; packages/{sdk,circuits,contracts}/src</code> returns the 9 frozen tags ONLY, no others. New invariant scan can be added to lint or CI in a follow-up.</li></ul><h2 id="_8-non-goals" tabindex="-1">8. Non-goals <a class="header-anchor" href="#_8-non-goals" aria-label="Permalink to &quot;8. Non-goals&quot;">​</a></h2><ul><li><strong>Renaming the 9 frozen consensus-critical tags.</strong> See §3.</li><li><strong>Force-pushing or rewriting git history.</strong> Old commits + tags retain historical names.</li><li><strong>Renaming the GitHub repo back to <code>identityescroworg</code>.</strong> It&#39;s now <code>alik-eth/zkqes</code> (renamed today); GitHub auto-redirects from the old URL, no source-side fix needed.</li><li><strong>Migrating V3/V4 R2 artifacts to a new bucket.</strong> The old bucket stays as-is.</li><li><strong>Re-running Phase B ceremony.</strong> Q3 freeze means circuit + ceremony stay valid.</li><li><strong>Renaming <code>IdentityEscrowNFT</code> references in already-published release notes (<code>docs/release-notes/v0.5.3-contracts.md</code> etc.).</strong> Those reference V5.x state at the time they were written; future release notes use the new name.</li></ul>',27)])])}const u=t(s,[["render",c]]);export{p as __pageData,u as default};
